#include <bits/stdc++.h>
using namespace std;

string subtractBinary(const string &b,const string &a){
    // b >= a, same length, returns binary (b-a) without leading zeros
    int n=b.size();
    string res(n,'0');
    int borrow=0;
    for(int i=n-1;i>=0;--i){
        int bi=b[i]-'0';
        int ai=a[i]-'0';
        int diff=bi-ai-borrow;
        if(diff<0){diff+=2;borrow=1;}else borrow=0;
        res[i]=char('0'+diff);
    }
    size_t pos=res.find('1');
    return pos==string::npos?"0":res.substr(pos);
}

string addBinary(const string &x,const string &y){
    int i=x.size()-1,j=y.size()-1,carry=0;string rev;
    while(i>=0||j>=0||carry){
        int sum=carry;
        if(i>=0) sum+=x[i--]-'0';
        if(j>=0) sum+=y[j--]-'0';
        rev.push_back(char('0'+(sum&1)));
        carry=sum>>1;
    }
    while(rev.size()>1&&rev.back()=='0') rev.pop_back();
    reverse(rev.begin(),rev.end());
    return rev;
}

string multiplyByTwo(const string &s){
    return s=="0"?"0":s+'0';
}

int popcount(const string &s){
    return (int)count(s.begin(),s.end(),'1');
}

string intToBinary(int v){
    if(v==0) return "0";
    string r;while(v){r.push_back('0'+(v&1));v>>=1;}reverse(r.begin(),r.end());return r;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int n; string a,b;cin>>n>>a>>b;
        string diff=subtractBinary(b,a); // b-a
        string twoDiff=multiplyByTwo(diff); // 2*(b-a)
        int pcDiff=popcount(b)-popcount(a);
        string pcStr=intToBinary(pcDiff);
        string result=subtractBinary(twoDiff,pcStr);
        size_t p=result.find('1');
        if(p==string::npos) result="0"; else result=result.substr(p);
        cout<<result<<"\n";
    }
    return 0;
}
